insert  into `t_article`(`id`,`title`,`summary`,`content`,`department_id`,`author`,`image`,`views`,`status`,`publish_time`,`create_time`,`update_time`) values (13,'高温天气如何预防中暑与热射病','夏季持续高温容易诱发中暑甚至热射病，本文整理了识别信号、应急处理和重点人群防护建议。','<p>持续高温天气会增加中暑与热射病的风险，老人、儿童、慢病患者和户外工作者更需重点防护。</p><h2>一、哪些人最容易中暑</h2><ul><li>长时间在户外工作或运动的人群</li><li>老年人、婴幼儿</li><li>肥胖、糖尿病、心血管疾病患者</li></ul><h2>二、早期信号</h2><p>包括头晕、口渴、乏力、恶心、心慌、大量出汗等，若出现意识模糊、高热、抽搐，应警惕热射病。</p><h2>三、现场处理</h2><p>立即转移至阴凉通风处，补充含电解质饮品，采用冷毛巾、喷雾、冰袋等方式降温，严重者应尽快送医。</p><h2>四、日常预防</h2><p>避开午后高温时段外出，穿浅色透气衣物，随身补水，不要在密闭车内久留。</p>','15','急诊医学科普组','img/health_01.jpeg',4120,1,'2026-07-01 09:00:00','2026-07-01 09:00:00','2026-07-01 09:00:00'),(14,'体检发现甲状腺结节后要不要紧张','甲状腺结节在体检中很常见，多数为良性。本文帮助您理解随访、检查与治疗边界。','<p>甲状腺结节并不等于甲状腺癌，大多数结节是良性的。</p><h2>一、先看超声分级</h2><p>超声会综合结节形态、边界、回声和钙化情况进行风险评估。</p><h2>二、什么时候需要穿刺</h2><p>若结节达到一定大小且提示中高风险，医生会建议细针穿刺明确性质。</p><h2>三、哪些情况需要尽快就诊</h2><ul><li>短期快速增大</li><li>伴声音嘶哑、吞咽困难</li><li>颈部淋巴结肿大</li></ul><h2>四、生活管理</h2><p>保持规律作息，不盲目补碘或停碘，按医嘱复查超声与甲功。</p>','39','内分泌门诊团队','img/health_02.jpeg',2860,1,'2026-07-02 08:30:00','2026-07-02 08:30:00','2026-07-02 08:30:00'),(15,'久坐办公人群的腰椎保护手册','腰酸背痛并不只是疲劳，长期久坐可能让腰椎间盘逐步退变。','<p>久坐、核心肌群薄弱和错误姿势，是办公室人群腰痛的常见诱因。</p><h2>一、办公姿势要点</h2><p>屏幕上缘与视线接近齐平，双脚平放地面，腰背有支撑，避免身体前探。</p><h2>二、每小时都该做什么</h2><p>建议每45到60分钟起身活动3到5分钟，可做后伸、侧屈和肩背舒展。</p><h2>三、哪些症状不能拖</h2><p>若出现腿麻、下肢放射痛、走路无力或大小便异常，应尽快就医。</p><h2>四、运动建议</h2><p>加强核心稳定训练，如平板支撑、桥式训练、游泳等，避免突然搬重物。</p>','40','脊柱外科康复组','img/health_03.jpeg',3510,1,'2026-07-03 10:10:00','2026-07-03 10:10:00','2026-07-03 10:10:00'),(16,'孩子反复咳嗽，到底是感冒还是过敏','儿童反复咳嗽可能与感染、鼻后滴流、哮喘或过敏有关，需要分情况观察。','<p>咳嗽是儿童门诊的常见主诉，但病因并不单一。</p><h2>一、常见原因</h2><ul><li>普通感冒恢复期</li><li>过敏性鼻炎伴鼻后滴流</li><li>咳嗽变异性哮喘</li><li>支原体等感染</li></ul><h2>二、家长该记录什么</h2><p>重点记录咳嗽时段、伴随发热与否、是否夜间明显、是否运动后加重。</p><h2>三、何时需要拍片或肺功能评估</h2><p>若咳嗽超过4周、反复喘息或治疗效果差，医生会进一步检查。</p>','44','儿童呼吸专科','img/health_01.jpeg',2988,1,'2026-07-04 14:00:00','2026-07-04 14:00:00','2026-07-04 14:00:00'),(17,'长期熬夜为什么会让血压失控','睡眠不足会影响交感神经、内分泌和血管舒缩功能，是高血压管理中的隐形因素。','<p>不少年轻高血压患者并非单纯饮食问题，作息紊乱同样是核心诱因。</p><h2>一、熬夜带来的连锁反应</h2><p>会导致应激激素升高、心率加快、第二天血压波动增大。</p><h2>二、哪些表现提示血压波动明显</h2><p>晨起头胀、心慌、易怒、夜间难入睡等都值得关注。</p><h2>三、管理建议</h2><p>固定睡眠时间、减少咖啡因摄入、规律监测血压，并结合运动与减盐。</p>','27','心血管健康研究室','img/health_02.jpeg',2745,1,'2026-07-05 11:40:00','2026-07-05 11:40:00','2026-07-05 11:40:00'),(18,'耳鸣反复发作时要做哪些检查','耳鸣并不一定只是耳朵问题，可能与听力、颈椎、压力和血管因素相关。','<p>耳鸣分为持续性、间断性、搏动性等多种类型，检查路径也不同。</p><h2>一、基础检查</h2><p>耳内镜、纯音测听、声导抗是最常见的第一步。</p><h2>二、哪些情况需要影像学</h2><p>单侧耳鸣、伴听力下降、眩晕、面瘫或搏动样耳鸣时，可能需要进一步评估。</p><h2>三、生活干预</h2><p>减少熬夜和噪声暴露，避免情绪紧张，必要时进行睡眠和焦虑评估。</p>','50','耳科专病组','img/health_03.jpeg',1886,1,'2026-07-06 16:20:00','2026-07-06 16:20:00','2026-07-06 16:20:00'),(19,'孕期血糖偏高，饮食管理怎么做','妊娠期糖尿病管理的关键在于饮食、运动、监测和定期产检。','<p>孕期血糖异常并不罕见，规范管理可显著降低母婴风险。</p><h2>一、三餐分配原则</h2><p>主食定量、粗细搭配，适量优质蛋白，减少高糖饮料和精制甜点。</p><h2>二、加餐怎么安排</h2><p>可根据血糖情况增加两到三次小加餐，避免空腹时间过长。</p><h2>三、运动建议</h2><p>饭后散步20到30分钟通常有助于血糖平稳，但需结合产科评估。</p>','54','产科营养门诊','img/health_01.jpeg',2430,1,'2026-07-07 09:20:00','2026-07-07 09:20:00','2026-07-07 09:20:00'),(20,'过敏性鼻炎总反复，如何减少发作频率','控制过敏原暴露、规范用药和鼻腔护理，是降低发作频率的三大基础。','<p>过敏性鼻炎患者常反复鼻塞、流涕、打喷嚏，影响睡眠和工作效率。</p><h2>一、家庭环境管理</h2><p>定期除螨、减少毛绒织物堆积、注意空调滤网清洁。</p><h2>二、药物使用误区</h2><p>鼻喷激素需要规范连续使用一段时间，并不是症状一缓解就立刻停药。</p><h2>三、合并哮喘时怎么办</h2><p>若合并喘息或胸闷，应同时评估下气道情况。</p>','51','耳鼻喉健康课堂','img/health_02.jpeg',3255,1,'2026-07-08 13:00:00','2026-07-08 13:00:00','2026-07-08 13:00:00'),(21,'乳腺结节筛查报告怎么看','乳腺影像分级是判断后续随访与检查的重要依据。','<p>很多女性在体检中首次发现乳腺结节后会非常焦虑，其实大部分结节并不危险。</p><h2>一、重点看什么</h2><p>关注结节边界、形态、血流、钙化以及影像分级。</p><h2>二、不同年龄的检查方式</h2><p>年轻女性多先做超声，40岁以上可结合钼靶评估。</p><h2>三、什么时候需要专科门诊</h2><p>结节增大快、局部皮肤改变、乳头溢液或家族史明显时，应及时就诊。</p>','53','妇科健康编辑部','img/health_03.jpeg',2172,1,'2026-07-09 15:30:00','2026-07-09 15:30:00','2026-07-09 15:30:00'),(22,'肺结节复查间隔应该怎么定','肺结节管理要结合大小、密度、边缘和风险因素综合判断，不能一概而论。','<p>随着低剂量 CT 普及，肺结节发现率越来越高，但并非发现结节就意味着恶性。</p><h2>一、常见分类</h2><p>可分为实性结节、磨玻璃结节和部分实性结节。</p><h2>二、随访为什么重要</h2><p>很多结节的关键不是一次检查，而是连续复查中的变化趋势。</p><h2>三、哪些人风险更高</h2><p>长期吸烟、有肿瘤家族史、既往肺部疾病人群应更加重视。</p>','34','呼吸慢病管理组','img/health_01.jpeg',3098,1,'2026-07-10 08:50:00','2026-07-10 08:50:00','2026-07-10 08:50:00'),(23,'老年人防跌倒要从家里开始改','老年跌倒既与肌力退化有关，也与家居环境和用药管理密切相关。','<p>防跌倒不是单一动作，而是环境改造、营养、视力、平衡训练的综合管理。</p><h2>一、家里最该改的地方</h2><p>浴室防滑、床边夜灯、去掉松散地毯、常用物品放在易取处。</p><h2>二、哪些药物要特别留意</h2><p>安眠药、部分降压药、镇静药可能增加跌倒风险，应咨询医生调整。</p><h2>三、训练建议</h2><p>可开展下肢力量训练、步态练习和平衡训练。</p>','55','老年医学中心','img/health_02.jpeg',1768,1,'2026-07-11 10:15:00','2026-07-11 10:15:00','2026-07-11 10:15:00'),(24,'情绪总是紧绷，如何区分压力和焦虑障碍','短期压力和持续性焦虑并不相同，关键在于持续时间、强度及对生活的影响。','<p>偶发紧张是正常反应，但若长期失眠、心慌、坐立不安并影响工作学习，就需要重视。</p><h2>一、焦虑的常见躯体表现</h2><p>包括胸闷、出汗、胃部不适、注意力下降和反复担心。</p><h2>二、什么时候建议求助</h2><p>若持续两周以上，且影响进食、睡眠、社交或工作，应考虑专业评估。</p><h2>三、日常干预</h2><p>规律作息、减少信息过载、运动和呼吸训练，都有助于缓解症状。</p>','44','心理睡眠联合门诊','img/health_03.jpeg',2644,1,'2026-07-12 17:10:00','2026-07-12 17:10:00','2026-07-12 17:10:00');

insert  into `t_hospital`(`id`,`name`,`level`,`address`,`phone`,`intro`,`image`,`province`,`city`,`department_count`,`doctor_count`,`follow_count`,`status`,`create_time`,`update_time`) values (27,'深圳市人民医院','三级甲等','广东省深圳市罗湖区东门北路1017号','0755-25533018','深圳市人民医院是集医疗、教学、科研、预防保健于一体的大型现代化综合医院。','img/hospital_100001977.jpg','广东省','深圳市',22,486,36210,1,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(28,'浙江大学医学院附属第二医院','三级甲等','浙江省杭州市上城区解放路88号','0571-87783777','浙大二院在创伤急救、神经医学、心血管疾病等领域具有较强综合实力。','img/hospital_14616536073112.jpg','浙江省','杭州市',24,528,40126,1,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(29,'南京市第一医院','三级甲等','江苏省南京市秦淮区长乐路68号','025-52271000','南京市第一医院承担区域急危重症救治和多学科协同诊疗任务。','img/hospital_16043929044175.jpg','江苏省','南京市',18,356,28753,1,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(30,'青岛大学附属医院','三级甲等','山东省青岛市市南区江苏路16号','0532-82911847','青大附院是山东半岛重要的疑难重症诊疗中心之一，专科设置完善。','img/hospital_16195932543164.png','山东省','青岛市',21,402,31548,1,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(31,'厦门大学附属第一医院','三级甲等','福建省厦门市思明区镇海路55号','0592-2132222','厦门大学附属第一医院在消化、肿瘤、妇产和心脑血管疾病诊疗方面积累丰富经验。','img/hospital_100001977.jpg','福建省','厦门市',19,344,26418,1,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(32,'昆明医科大学第一附属医院','三级甲等','云南省昆明市西山区西昌路295号','0871-65324888','昆医大附一院是云南省综合实力较强的三级甲等医院，辐射西南周边地区。','img/hospital_14616536073112.jpg','云南省','昆明市',20,378,28966,1,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(33,'哈尔滨医科大学附属第一医院','三级甲等','黑龙江省哈尔滨市南岗区邮政街23号','0451-85556000','哈医大一院在东北地区具有较强影响力，擅长多学科联合和疑难疾病救治。','img/hospital_16043929044175.jpg','黑龙江省','哈尔滨市',23,451,33882,1,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(34,'南昌大学第一附属医院','三级甲等','江西省南昌市东湖区永外正街17号','0791-88692748','南昌大学第一附属医院承担区域医疗中心功能，心脑血管、呼吸和消化专科建设较完善。','img/hospital_16195932543164.png','江西省','南昌市',18,332,25164,1,'2026-07-01 09:00:00','2026-07-01 09:00:00');

