insert  into `t_disease`(`id`,`department_id`,`name`,`description`,`alias`,`location`,`treatment`,`symptoms`,`treatment_period`,`cure_rate`,`examinations`,`follow_count`,`create_time`,`update_time`) values (100,27,'继发性高血压','由肾脏、内分泌或血管等明确病因引起的高血压综合征。','症状性高血压','全身、心脑肾血管','病因治疗、降压治疗、并发症预防','血压持续升高、头痛、心悸、视物模糊','长期管理','明确病因后可改善','动态血压、肾功能、激素水平、影像学',2860,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(101,27,'高血压脑病','血压急剧升高引起脑循环调节障碍，表现为头痛、呕吐和意识改变。','高血压急症脑损害','大脑','快速但平稳降压、监护治疗','剧烈头痛、呕吐、烦躁、意识障碍','急性期处理','及时处理预后较好','血压监测、头颅CT、眼底检查',1450,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(102,26,'房颤','心房快速而不规则电活动导致的常见心律失常，可增加卒中风险。','心房颤动','心脏','抗凝、控率、复律、消融治疗','心悸、乏力、胸闷、头晕','长期管理','多数可控制','心电图、动态心电图、超声心动图',5320,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(103,26,'扩张型心肌病','心室扩大并伴收缩功能减退的一类心肌疾病。','DCM','心脏','药物治疗、器械治疗、心衰管理','气短、乏力、水肿、夜间憋醒','长期治疗','可延缓进展','心脏超声、心电图、BNP、心脏MRI',2186,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(104,29,'短暂性脑缺血发作','脑局部供血短暂不足引起神经功能障碍，症状通常在24小时内恢复。','TIA','大脑血管','抗血小板、降脂、病因评估','一过性肢体无力、言语不清、视物发黑','短期急诊评估后长期管理','可明显降低复发风险','头颅MRI、颈动脉超声、心电图',3268,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(105,29,'脑动脉狭窄','脑供血动脉因动脉粥样硬化等原因出现狭窄，增加卒中风险。','颅内外动脉狭窄','脑血管','药物控制、介入评估、危险因素管理','头晕、肢体麻木、短暂黑朦','长期管理','规范管理可降低风险','CTA、MRA、颈动脉超声、血脂血糖',1936,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(106,30,'偏头痛','反复发作的中重度头痛，可伴恶心、畏光和先兆。','Migraine','头部','止痛药、预防用药、诱因管理','搏动样头痛、恶心、怕光、怕声','长期管理','大多可控制','头痛评估、神经系统检查、必要时影像学',4782,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(107,31,'特发性震颤','以姿势性或动作性震颤为主要表现的常见运动障碍。','原发性震颤','上肢、头部','药物治疗、神经调控、生活方式调整','手抖、写字不稳、端杯洒水','长期管理','可改善症状','神经系统查体、家族史评估、排除性检查',1388,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(108,32,'支气管扩张','支气管异常且持久扩张，可反复感染和咳脓痰。','支扩','支气管','抗感染、排痰、雾化、肺康复','长期咳嗽、咳痰、咯血、反复发热','长期管理','规范治疗可稳定','胸部CT、痰培养、肺功能',2562,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(109,32,'慢性咳嗽','持续超过8周的咳嗽，病因复杂，可与上气道、气道高反应或反流有关。','久咳','呼吸道','病因筛查、针对性治疗','咳嗽迁延、夜间咳、咽痒','视病因而定','多数可改善','胸片、肺功能、FeNO、过敏评估',3015,'2026-07-01 09:00:00','2026-07-01 09:00:00'),(110,3